7	 * Fuzzing harness: committed datatype open and introspection.
8	 *
9	 * Strategy
10	 * --------
11	 * One-time init (LLVMFuzzerInitialize):
12	 *   Build a minimal valid HDF5 file entirely in RAM using the CORE VFD,
13	 *   commit five named datatypes covering every interesting class
14	 *   (compound with nested sub-compound, enum, variable-length string,
15	 *   array, opaque), then capture the raw file bytes via H5Fget_file_image.
16	 *
17	 * Per-iteration (LLVMFuzzerTestOneInput):
18	 *   Copy the golden image, overwrite the region AFTER the superblock
19	 *   (bytes >= SAFE_OFFSET) with fuzz bytes, then load the mutated image
20	 *   back into a CORE VFD file via H5Pset_file_image + H5Fopen.  For each
21	 *   known type name, call H5Topen2 and walk the full introspection chain
22	 *   (H5Tget_class, H5Tget_size, H5Tget_nmembers, H5Tget_member_type,
23	 *   H5Tget_member_offset, H5Tis_variable_str, H5Tget_super, H5Tclose).
24	 *
25	 * The superblock magic (\x89HDF\r\n\x1a\n) at bytes 0-7 is left intact so
26	 * H5Fopen can open the file; everything from byte SAFE_OFFSET onward –
27	 * including the object headers that encode the type descriptors – is
28	 * handed directly to the fuzzer.
29	 */
30	
31	#include "hdf5.h"      /* includes H5FDcore.h */
32	
33	#include <stdint.h>
34	#include <stdlib.h>
35	#include <string.h>
36	
37	/* Bytes to protect at the start of the image (superblock signature region) */
38	#define SAFE_OFFSET 512
39	
40	/* Names of committed types baked into the golden image */
41	#define TN_COMPOUND "cmpd"
42	#define TN_ENUM     "enum"
43	#define TN_VLSTR    "vlstr"
44	#define TN_ARRAY    "arr"
45	#define TN_OPAQUE   "opq"
46	
47	static const char * const g_names[] = {
48	    TN_COMPOUND, TN_ENUM, TN_VLSTR, TN_ARRAY, TN_OPAQUE, NULL
49	};
50	
51	static unsigned char *g_golden    = NULL;
52	static size_t         g_golden_sz = 0;
53	
54	/* ------------------------------------------------------------------ */
55	/* Recursive type introspection (depth-limited)                        */
56	/* ------------------------------------------------------------------ */
57	static void
58	introspect(hid_t tid, int depth)
59	{
60	    if (depth > 5 || tid < 0)
61	        return;
62	
63	    H5T_class_t cls = H5Tget_class(tid);
64	    (void)H5Tget_size(tid);
65	    (void)H5Tis_variable_str(tid);
66	
67	    switch (cls) {
68	    case H5T_COMPOUND: {
69	        int n = H5Tget_nmembers(tid);
70	        for (int i = 0; i < n && i < 64; i++) {
71	            (void)H5Tget_member_offset(tid, (unsigned)i);
72	            hid_t mt = H5Tget_member_type(tid, (unsigned)i);
73	            if (mt >= 0) {
74	                introspect(mt, depth + 1);
75	                H5Tclose(mt);
76	            }
77	        }
78	        break;
79	    }
80	    case H5T_ENUM: {
81	        (void)H5Tget_nmembers(tid);
82	        /* fall through to read the base integer type */
83	        hid_t super = H5Tget_super(tid);
84	        if (super >= 0) {
85	            introspect(super, depth + 1);
86	            H5Tclose(super);
87	        }
88	        break;
89	    }
90	    case H5T_VLEN:
91	    case H5T_ARRAY: {
92	        hid_t super = H5Tget_super(tid);
93	        if (super >= 0) {
94	            introspect(super, depth + 1);
95	            H5Tclose(super);
96	        }
97	        break;
98	    }
99	    default:
100	        break;
101	    }
102	}
103	
104	/* ------------------------------------------------------------------ */
105	/* Build the golden in-memory HDF5 file with committed types           */
106	/* ------------------------------------------------------------------ */
107	static int
108	build_golden(void)
109	{
110	    hid_t fapl  = H5I_INVALID_HID;
111	    hid_t fid   = H5I_INVALID_HID;
112	    hid_t cmpd  = H5I_INVALID_HID;
113	    hid_t icmpd = H5I_INVALID_HID;
114	    hid_t enm   = H5I_INVALID_HID;
115	    hid_t vlstr = H5I_INVALID_HID;
116	    hid_t arr   = H5I_INVALID_HID;
117	    hid_t opq   = H5I_INVALID_HID;
118	    ssize_t isz;
119	    int ival;
120	
121	    fapl = H5Pcreate(H5P_FILE_ACCESS);
122	    if (fapl < 0)
123	        return -1;
124	
125	    /* Pure-in-memory CORE VFD, no disk backing */
126	    if (H5Pset_fapl_core(fapl, (size_t)(2 * 1024 * 1024), false) < 0)
127	        goto fail;
128	
129	    fid = H5Fcreate("__fuzz_golden.h5", H5F_ACC_TRUNC, H5P_DEFAULT, fapl);
130	    if (fid < 0)
131	        goto fail;
132	
133	    /* ---- Compound type: outer(24 bytes) + inner sub-compound(12 bytes) ---- */
134	    /*
135	     * outer layout (24 bytes total):
136	     *   x      : int   at offset  0  (4 bytes)
137	     *   y      : float at offset  4  (4 bytes)
138	     *   inner  : icmpd at offset  8  (12 bytes)  -> bytes 8..19
139	     *   padding:                  20..23
140	     *
141	     * inner layout (12 bytes total):
142	     *   a      : double at offset 0  (8 bytes)
143	     *   b      : int    at offset 8  (4 bytes)
144	     */
145	    icmpd = H5Tcreate(H5T_COMPOUND, 12);
146	    if (icmpd < 0) goto fail;
147	    if (H5Tinsert(icmpd, "a", 0, H5T_NATIVE_DOUBLE) < 0) goto fail;
148	    if (H5Tinsert(icmpd, "b", 8, H5T_NATIVE_INT)    < 0) goto fail;
149	
150	    cmpd = H5Tcreate(H5T_COMPOUND, 24);
151	    if (cmpd < 0) goto fail;
152	    if (H5Tinsert(cmpd, "x",     0, H5T_NATIVE_INT)   < 0) goto fail;
153	    if (H5Tinsert(cmpd, "y",     4, H5T_NATIVE_FLOAT) < 0) goto fail;
154	    if (H5Tinsert(cmpd, "inner", 8, icmpd)             < 0) goto fail;
155	    H5Tclose(icmpd); icmpd = H5I_INVALID_HID;
156	
157	    if (H5Tcommit2(fid, TN_COMPOUND, cmpd,
158	                   H5P_DEFAULT, H5P_DEFAULT, H5P_DEFAULT) < 0) goto fail;
159	    H5Tclose(cmpd); cmpd = H5I_INVALID_HID;
160	
161	    /* ---- Enum type (int base with three named values) ---- */
162	    enm = H5Tenum_create(H5T_NATIVE_INT);
163	    if (enm < 0) goto fail;
164	    ival = 0; if (H5Tenum_insert(enm, "RED",   &ival) < 0) goto fail;
165	    ival = 1; if (H5Tenum_insert(enm, "GREEN", &ival) < 0) goto fail;
166	    ival = 2; if (H5Tenum_insert(enm, "BLUE",  &ival) < 0) goto fail;
167	    if (H5Tcommit2(fid, TN_ENUM, enm,
168	                   H5P_DEFAULT, H5P_DEFAULT, H5P_DEFAULT) < 0) goto fail;
169	    H5Tclose(enm); enm = H5I_INVALID_HID;
170	
171	    /* ---- Variable-length string type ---- */
172	    vlstr = H5Tcopy(H5T_C_S1);
173	    if (vlstr < 0) goto fail;
174	    if (H5Tset_size(vlstr, H5T_VARIABLE) < 0) goto fail;
175	    if (H5Tcommit2(fid, TN_VLSTR, vlstr,
176	                   H5P_DEFAULT, H5P_DEFAULT, H5P_DEFAULT) < 0) goto fail;
177	    H5Tclose(vlstr); vlstr = H5I_INVALID_HID;
178	
179	    /* ---- Array type: 1-D array of 4 ints ---- */
180	    {
181	        hsize_t dims[1] = {4};
182	        arr = H5Tarray_create2(H5T_NATIVE_INT, 1, dims);
183	    }
184	    if (arr < 0) goto fail;
185	    if (H5Tcommit2(fid, TN_ARRAY, arr,
186	                   H5P_DEFAULT, H5P_DEFAULT, H5P_DEFAULT) < 0) goto fail;
187	    H5Tclose(arr); arr = H5I_INVALID_HID;
188	
189	    /* ---- Opaque type (8 bytes, tagged) ---- */
190	    opq = H5Tcreate(H5T_OPAQUE, 8);
191	    if (opq < 0) goto fail;
192	    if (H5Tset_tag(opq, "blob") < 0) goto fail;
193	    if (H5Tcommit2(fid, TN_OPAQUE, opq,
194	                   H5P_DEFAULT, H5P_DEFAULT, H5P_DEFAULT) < 0) goto fail;
195	    H5Tclose(opq); opq = H5I_INVALID_HID;
196	
197	    /* Flush and capture the raw image */
198	    if (H5Fflush(fid, H5F_SCOPE_GLOBAL) < 0) goto fail;
199	    isz = H5Fget_file_image(fid, NULL, 0);
200	    if (isz <= 0) goto fail;
201	    g_golden = (unsigned char *)malloc((size_t)isz);
202	    if (!g_golden) goto fail;
203	    if (H5Fget_file_image(fid, g_golden, (size_t)isz) < 0) {
204	        free(g_golden);
205	        g_golden = NULL;
206	        goto fail;
207	    }
208	    g_golden_sz = (size_t)isz;
209	
210	    H5Fclose(fid);
211	    H5Pclose(fapl);
212	    return 0;
213	
214	fail:
215	    if (icmpd != H5I_INVALID_HID) H5Tclose(icmpd);
216	    if (cmpd  != H5I_INVALID_HID) H5Tclose(cmpd);
217	    if (enm   != H5I_INVALID_HID) H5Tclose(enm);
218	    if (vlstr != H5I_INVALID_HID) H5Tclose(vlstr);
219	    if (arr   != H5I_INVALID_HID) H5Tclose(arr);
220	    if (opq   != H5I_INVALID_HID) H5Tclose(opq);
221	    if (fid   != H5I_INVALID_HID) H5Fclose(fid);
222	    if (fapl  != H5I_INVALID_HID) H5Pclose(fapl);
223	    return -1;
224	}
