226	/* ------------------------------------------------------------------ */
227	/* Fuzzer entry points                                                  */
228	/* ------------------------------------------------------------------ */
229	
230	int LLVMFuzzerInitialize(int *argc, char ***argv)
231	{
232	    (void)argc;
233	    (void)argv;
234	    /* Suppress all HDF5 error output during fuzzing */
235	    H5Eset_auto2(H5E_DEFAULT, NULL, NULL);
236	    build_golden();
237	    return 0;
238	}
239	
240	int LLVMFuzzerTestOneInput(const uint8_t *data, size_t size)
241	{
242	    if (!g_golden || g_golden_sz < SAFE_OFFSET)
243	        return 0;
244	
245	    /* Copy the golden image and overlay fuzz bytes past the superblock */
246	    unsigned char *img = (unsigned char *)malloc(g_golden_sz);
247	    if (!img)
248	        return 0;
249	    memcpy(img, g_golden, g_golden_sz);
250	
251	    if (size > 0) {
252	        size_t mutable_region = g_golden_sz - SAFE_OFFSET;
253	        size_t copy_len = (size < mutable_region) ? size : mutable_region;
254	        memcpy(img + SAFE_OFFSET, data, copy_len);
255	    }
256	
257	    /* Open the mutated image via CORE VFD (no disk backing) */
258	    hid_t fapl = H5Pcreate(H5P_FILE_ACCESS);
259	    if (fapl < 0) {
260	        free(img);
261	        return 0;
262	    }
263	    if (H5Pset_fapl_core(fapl, (size_t)(64 * 1024), false) < 0 ||
264	        H5Pset_file_image(fapl, img, g_golden_sz) < 0) {
265	        H5Pclose(fapl);
266	        free(img);
267	        return 0;
268	    }
269	    free(img);  /* H5Pset_file_image made its own internal copy */
270	
271	    hid_t fid = H5Fopen("__fuzz_golden.h5", H5F_ACC_RDONLY, fapl);
272	    H5Pclose(fapl);
273	    if (fid < 0)
274	        return 0;
275	
276	    /* Open each committed type and exercise the full introspection chain */
277	    for (int i = 0; g_names[i] != NULL; i++) {
278	        hid_t tid = H5Topen2(fid, g_names[i], H5P_DEFAULT);
279	        if (tid < 0)
280	            continue;
281	        introspect(tid, 0);
282	        H5Tclose(tid);
283	    }
284	
285	    H5Fclose(fid);
286	    return 0;
287	}
