 *
 * Fuzzing harness: committed datatype open and introspection.
 *
 * Strategy
 * --------
 * One-time init (LLVMFuzzerInitialize):
 *   Build a minimal valid HDF5 file entirely in RAM using the CORE VFD,
 *   commit five named datatypes covering every interesting class
 *   (compound with nested sub-compound, enum, variable-length string,
 *   array, opaque), then capture the raw file bytes via H5Fget_file_image.
 *
 * Per-iteration (LLVMFuzzerTestOneInput):
 *   Copy the golden image, overwrite the region AFTER the superblock
 *   (bytes >= SAFE_OFFSET) with fuzz bytes, then load the mutated image
 *   back into a CORE VFD file via H5Pset_file_image + H5Fopen.  For each
 *   known type name, call H5Topen2 and walk the full introspection chain
 *   (H5Tget_class, H5Tget_size, H5Tget_nmembers, H5Tget_member_type,
 *   H5Tget_member_offset, H5Tis_variable_str, H5Tget_super, H5Tclose).
 *
 * The superblock magic (\x89HDF\r\n\x1a\n) at bytes 0-7 is left intact so
 * H5Fopen can open the file; everything from byte SAFE_OFFSET onward –
 * including the object headers that encode the type descriptors – is
 * handed directly to the fuzzer.
 */

#include "hdf5.h"      /* includes H5FDcore.h */

#include <stdint.h>
#include <stdlib.h>
#include <string.h>

/* Bytes to protect at the start of the image (superblock signature region) */
#define SAFE_OFFSET 512

/* Names of committed types baked into the golden image */
#define TN_COMPOUND "cmpd"
#define TN_ENUM     "enum"
#define TN_VLSTR    "vlstr"
#define TN_ARRAY    "arr"
#define TN_OPAQUE   "opq"

static const char * const g_names[] = {
    TN_COMPOUND, TN_ENUM, TN_VLSTR, TN_ARRAY, TN_OPAQUE, NULL
};

static unsigned char *g_golden    = NULL;
static size_t         g_golden_sz = 0;

/* ------------------------------------------------------------------ */
/* Recursive type introspection (depth-limited)                        */
/* ------------------------------------------------------------------ */
static void
introspect(hid_t tid, int depth)
{
    if (depth > 5 || tid < 0)
        return;

    H5T_class_t cls = H5Tget_class(tid);
    (void)H5Tget_size(tid);
    (void)H5Tis_variable_str(tid);

    switch (cls) {
    case H5T_COMPOUND: {
        int n = H5Tget_nmembers(tid);
        for (int i = 0; i < n && i < 64; i++) {
            (void)H5Tget_member_offset(tid, (unsigned)i);
            hid_t mt = H5Tget_member_type(tid, (unsigned)i);
            if (mt >= 0) {
                introspect(mt, depth + 1);
                H5Tclose(mt);
            }
        }
        break;
    }
    case H5T_ENUM: {
        (void)H5Tget_nmembers(tid);
        /* fall through to read the base integer type */
        hid_t super = H5Tget_super(tid);
        if (super >= 0) {
            introspect(super, depth + 1);
            H5Tclose(super);
        }
        break;
    }
    case H5T_VLEN:
    case H5T_ARRAY: {
        hid_t super = H5Tget_super(tid);
        if (super >= 0) {
            introspect(super, depth + 1);
            H5Tclose(super);
        }
        break;
    }
    default:
        break;
    }
}

/* ------------------------------------------------------------------ */
/* Build the golden in-memory HDF5 file with committed types           */
/* ------------------------------------------------------------------ */
static int
build_golden(void)
{
    hid_t fapl  = H5I_INVALID_HID;
    hid_t fid   = H5I_INVALID_HID;
    hid_t cmpd  = H5I_INVALID_HID;
    hid_t icmpd = H5I_INVALID_HID;
    hid_t enm   = H5I_INVALID_HID;
    hid_t vlstr = H5I_INVALID_HID;
    hid_t arr   = H5I_INVALID_HID;
    hid_t opq   = H5I_INVALID_HID;
    ssize_t isz;
    int ival;

    fapl = H5Pcreate(H5P_FILE_ACCESS);
    if (fapl < 0)
        return -1;

    /* Pure-in-memory CORE VFD, no disk backing */
    if (H5Pset_fapl_core(fapl, (size_t)(2 * 1024 * 1024), false) < 0)
        goto fail;

    fid = H5Fcreate("__fuzz_golden.h5", H5F_ACC_TRUNC, H5P_DEFAULT, fapl);
    if (fid < 0)
        goto fail;

    /* ---- Compound type: outer(24 bytes) + inner sub-compound(12 bytes) ---- */
    /*
     * outer layout (24 bytes total):
     *   x      : int   at offset  0  (4 bytes)
     *   y      : float at offset  4  (4 bytes)
     *   inner  : icmpd at offset  8  (12 bytes)  -> bytes 8..19
     *   padding:                  20..23
     *
     * inner layout (12 bytes total):
     *   a      : double at offset 0  (8 bytes)
     *   b      : int    at offset 8  (4 bytes)
     */
    icmpd = H5Tcreate(H5T_COMPOUND, 12);
    if (icmpd < 0) goto fail;
    if (H5Tinsert(icmpd, "a", 0, H5T_NATIVE_DOUBLE) < 0) goto fail;
    if (H5Tinsert(icmpd, "b", 8, H5T_NATIVE_INT)    < 0) goto fail;

    cmpd = H5Tcreate(H5T_COMPOUND, 24);
    if (cmpd < 0) goto fail;
    if (H5Tinsert(cmpd, "x",     0, H5T_NATIVE_INT)   < 0) goto fail;
    if (H5Tinsert(cmpd, "y",     4, H5T_NATIVE_FLOAT) < 0) goto fail;
    if (H5Tinsert(cmpd, "inner", 8, icmpd)             < 0) goto fail;
    H5Tclose(icmpd); icmpd = H5I_INVALID_HID;

    if (H5Tcommit2(fid, TN_COMPOUND, cmpd,
                   H5P_DEFAULT, H5P_DEFAULT, H5P_DEFAULT) < 0) goto fail;
    H5Tclose(cmpd); cmpd = H5I_INVALID_HID;

    /* ---- Enum type (int base with three named values) ---- */
    enm = H5Tenum_create(H5T_NATIVE_INT);
    if (enm < 0) goto fail;
    ival = 0; if (H5Tenum_insert(enm, "RED",   &ival) < 0) goto fail;
    ival = 1; if (H5Tenum_insert(enm, "GREEN", &ival) < 0) goto fail;
    ival = 2; if (H5Tenum_insert(enm, "BLUE",  &ival) < 0) goto fail;
    if (H5Tcommit2(fid, TN_ENUM, enm,
                   H5P_DEFAULT, H5P_DEFAULT, H5P_DEFAULT) < 0) goto fail;
    H5Tclose(enm); enm = H5I_INVALID_HID;

    /* ---- Variable-length string type ---- */
    vlstr = H5Tcopy(H5T_C_S1);
    if (vlstr < 0) goto fail;
    if (H5Tset_size(vlstr, H5T_VARIABLE) < 0) goto fail;
    if (H5Tcommit2(fid, TN_VLSTR, vlstr,
                   H5P_DEFAULT, H5P_DEFAULT, H5P_DEFAULT) < 0) goto fail;
    H5Tclose(vlstr); vlstr = H5I_INVALID_HID;

    /* ---- Array type: 1-D array of 4 ints ---- */
    {
        hsize_t dims[1] = {4};
        arr = H5Tarray_create2(H5T_NATIVE_INT, 1, dims);
    }
    if (arr < 0) goto fail;
    if (H5Tcommit2(fid, TN_ARRAY, arr,
                   H5P_DEFAULT, H5P_DEFAULT, H5P_DEFAULT) < 0) goto fail;
    H5Tclose(arr); arr = H5I_INVALID_HID;

    /* ---- Opaque type (8 bytes, tagged) ---- */
    opq = H5Tcreate(H5T_OPAQUE, 8);
    if (opq < 0) goto fail;
    if (H5Tset_tag(opq, "blob") < 0) goto fail;
    if (H5Tcommit2(fid, TN_OPAQUE, opq,
                   H5P_DEFAULT, H5P_DEFAULT, H5P_DEFAULT) < 0) goto fail;
    H5Tclose(opq); opq = H5I_INVALID_HID;

    /* Flush and capture the raw image */
    if (H5Fflush(fid, H5F_SCOPE_GLOBAL) < 0) goto fail;
    isz = H5Fget_file_image(fid, NULL, 0);
    if (isz <= 0) goto fail;
    g_golden = (unsigned char *)malloc((size_t)isz);
    if (!g_golden) goto fail;
    if (H5Fget_file_image(fid, g_golden, (size_t)isz) < 0) {
        free(g_golden);
        g_golden = NULL;
        goto fail;
    }
    g_golden_sz = (size_t)isz;

    H5Fclose(fid);
    H5Pclose(fapl);
    return 0;

fail:
    if (icmpd != H5I_INVALID_HID) H5Tclose(icmpd);
    if (cmpd  != H5I_INVALID_HID) H5Tclose(cmpd);
    if (enm   != H5I_INVALID_HID) H5Tclose(enm);
    if (vlstr != H5I_INVALID_HID) H5Tclose(vlstr);
    if (arr   != H5I_INVALID_HID) H5Tclose(arr);
    if (opq   != H5I_INVALID_HID) H5Tclose(opq);
    if (fid   != H5I_INVALID_HID) H5Fclose(fid);
    if (fapl  != H5I_INVALID_HID) H5Pclose(fapl);
    return -1;
}

/* ------------------------------------------------------------------ */
/* Fuzzer entry points                                                  */
/* ------------------------------------------------------------------ */

int LLVMFuzzerInitialize(int *argc, char ***argv)
{
    (void)argc;
    (void)argv;
    /* Suppress all HDF5 error output during fuzzing */
    H5Eset_auto2(H5E_DEFAULT, NULL, NULL);
    build_golden();
    return 0;
}

int LLVMFuzzerTestOneInput(const uint8_t *data, size_t size)
{
    if (!g_golden || g_golden_sz < SAFE_OFFSET)
        return 0;

    /* Copy the golden image and overlay fuzz bytes past the superblock */
    unsigned char *img = (unsigned char *)malloc(g_golden_sz);
    if (!img)
        return 0;
    memcpy(img, g_golden, g_golden_sz);

    if (size > 0) {
        size_t mutable_region = g_golden_sz - SAFE_OFFSET;
        size_t copy_len = (size < mutable_region) ? size : mutable_region;
        memcpy(img + SAFE_OFFSET, data, copy_len);
    }

    /* Open the mutated image via CORE VFD (no disk backing) */
    hid_t fapl = H5Pcreate(H5P_FILE_ACCESS);
    if (fapl < 0) {
        free(img);
        return 0;
    }
    if (H5Pset_fapl_core(fapl, (size_t)(64 * 1024), false) < 0 ||
        H5Pset_file_image(fapl, img, g_golden_sz) < 0) {
        H5Pclose(fapl);
        free(img);
        return 0;
    }
    free(img);  /* H5Pset_file_image made its own internal copy */

    hid_t fid = H5Fopen("__fuzz_golden.h5", H5F_ACC_RDONLY, fapl);
    H5Pclose(fapl);
    if (fid < 0)
        return 0;

    /* Open each committed type and exercise the full introspection chain */
    for (int i = 0; g_names[i] != NULL; i++) {
        hid_t tid = H5Topen2(fid, g_names[i], H5P_DEFAULT);
        if (tid < 0)
            continue;
        introspect(tid, 0);
        H5Tclose(tid);
    }

    H5Fclose(fid);
    return 0;
}
